class Solution:
    def minimizeXor(self, num1, num2):
        k = bin(num2).count('1')
        x = 0
        # set shared high bits of num1 first
        for b in range(30, -1, -1):
            if k == 0:
                break
            if (num1 >> b) & 1:
                x |= (1 << b)
                k -= 1
        # fill remaining from lowest clear bits
        b = 0
        while k > 0:
            if not ((x >> b) & 1):
                x |= (1 << b)
                k -= 1
            b += 1
        return x

