var minimizeXor = function(num1, num2) {
    let k = 0;
    let t = num2;
    while (t > 0) { k += t & 1; t = Math.floor(t / 2); }
    let x = 0;
    for (let b = 30; b >= 0; b--) {
        if (k === 0) break;
        if ((num1 >> b) & 1) {
            x |= (1 << b);
            k--;
        }
    }
    let b = 0;
    while (k > 0) {
        if (!((x >> b) & 1)) {
            x |= (1 << b);
            k--;
        }
        b++;
    }
    return x >>> 0;
};
